import{_ as t,C as o,o as s,c as l,E as r,w as n,a as i,a0 as g}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Norway Legal Rights","description":"Legal rights for transgender people in Norway","frontmatter":{"layout":"doc","title":"Norway Legal Rights","description":"Legal rights for transgender people in Norway"},"headers":[],"relativePath":"europe/norway/legal-rights.md","filePath":"europe/norway/legal-rights.md","lastUpdated":null}'),d={name:"europe/norway/legal-rights.md"};function c(h,e,p,m,u,f){const a=o("Badge");return s(),l("div",null,[r(a,{variant:"yellow"},{default:n(()=>[...e[0]||(e[0]=[i("Self-ID since 2016",-1)])]),_:1}),r(a,{variant:"green"},{default:n(()=>[...e[1]||(e[1]=[i("Strong Hate Crime Laws",-1)])]),_:1}),e[2]||(e[2]=g('<h1 id="legal-rights-in-norway" tabindex="-1">Legal Rights in Norway <a class="header-anchor" href="#legal-rights-in-norway" aria-label="Permalink to &quot;Legal Rights in Norway&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Norway adopted a self-determination model for legal gender recognition in June 2016 (Law on the Change of Legal Gender). The law allows individuals aged 16 and over to change their legal gender through a simple online or written application to the <strong>Norwegian Tax Administration (Skatteetaten)</strong>.</p><p>The process:</p><ul><li>Online application or paper form</li><li>No medical certificates, surgery, or diagnosis required</li><li>No waiting period or reflection period</li><li>For minors aged 6-15, parental consent is required</li><li>Minors under 6 require special consideration</li></ul><p>Norway was one of the first countries to allow legal gender change for minors with parental consent.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes are processed through the same system (Skatteetaten). After legal gender recognition, a new first name can be chosen as part of the same application. Name-only changes (without gender marker change) follow a separate but equally simple process.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Norway has strong anti-discrimination protections:</p><ul><li><strong>Equality and Anti-Discrimination Act (Likestillings- og diskrimineringsloven)</strong> — Explicitly prohibits discrimination based on gender identity and gender expression</li><li><strong>Employment</strong> — Full protection in hiring, working conditions, and termination</li><li><strong>Healthcare</strong> — Right to access gender affirming care</li><li><strong>Education</strong> — Protection in all educational institutions</li><li><strong>Housing and services</strong> — Comprehensive protection</li></ul><p>The <strong>Equality and Anti-Discrimination Ombud (Likestillings- og diskrimineringsombudet)</strong> enforces these protections.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Norway&#39;s Penal Code (Straffeloven) provides enhanced penalties for hate crimes. Section 185 prohibits hate speech, and Section 186 prohibits discrimination. Gender identity and gender expression are explicitly included as protected characteristics. Crimes motivated by transphobia carry enhanced sentences.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Skatteetaten</strong> — Gender recognition applications: <a href="https://www.skatteetaten.no/" target="_blank" rel="noreferrer">skatteetaten.no</a></li><li><strong>FRI - Foreningen for kjønns- og seksualitetsmangfold</strong> — <a href="https://foreningenfri.no/" target="_blank" rel="noreferrer">foreningenfri.no</a></li><li><strong>Likestillings- og diskrimineringsombudet</strong> — <a href="https://www.ldo.no/" target="_blank" rel="noreferrer">ldo.no</a></li><li><strong>ILGA-Europe - Norway Country Report</strong> — <a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ilga-europe.org</a></li><li><strong>Harry Benjamin Resource Centre</strong> — Trans health and legal support: <a href="https://hbrs.no/" target="_blank" rel="noreferrer">hbrs.no</a></li></ul>',16))])}const b=t(d,[["render",c]]);export{y as __pageData,b as default};
